      payload:
        | "all"
        | "struggling"
        | "learning"
        | "proficient"
        | "mastered"
        | "not-practiced";
    };

function searchReducer(state: SearchState, action: SearchAction): SearchState {
  switch (action.type) {
    case "SET_QUERY":
