+import { UserProfileWithHistory } from "@/types/userProfile";
+
+const USER_PROFILE_KEY = "userProfile";
+
+const defaultProfile: UserProfileWithHistory = {
+  totalXP: 0,
+  level: 1,
+  questionsAnswered: 0,
+  correctAnswers: 0,
+  answeredQuestionIds: [],
+  lastUpdated: Date.now(),
+};
+
+const calculateLevel = (xp: number) => Math.max(1, Math.floor(xp / 500) + 1);
+
+export function getUserProfile(): UserProfileWithHistory {
+  if (typeof window === "undefined") return defaultProfile;
+
+  try {
+    const stored = localStorage.getItem(USER_PROFILE_KEY);
+    return stored ? { ...defaultProfile, ...JSON.parse(stored) } : defaultProfile;
+  } catch {
+    return defaultProfile;
+  }
+}
+
+export function saveUserProfile(profile: UserProfileWithHistory) {
+  if (typeof window === "undefined") return;
+  localStorage.setItem(USER_PROFILE_KEY, JSON.stringify(profile));
+}
+
+export function addXPForCorrectAnswer(
+  questionId: string,
+  scoreBandRange = 1
+): UserProfileWithHistory {
+  const profile = getUserProfile();
+  const xpGain = Math.max(1, scoreBandRange) * 10;
+  const nextProfile: UserProfileWithHistory = {
+    ...profile,
+    totalXP: profile.totalXP + xpGain,
+    level: calculateLevel(profile.totalXP + xpGain),
+    questionsAnswered: profile.questionsAnswered + 1,
+    correctAnswers: profile.correctAnswers + 1,
+    answeredQuestionIds: profile.answeredQuestionIds.includes(questionId)
+      ? profile.answeredQuestionIds
+      : [...profile.answeredQuestionIds, questionId],
+    lastUpdated: Date.now(),
+  };
+
+  saveUserProfile(nextProfile);
+  return nextProfile;
+}
+
+export function reduceXPForIncorrectAnswer(
+  questionId: string,
+  scoreBandRange = 1
+): UserProfileWithHistory {
+  const profile = getUserProfile();
+  const xpLoss = Math.max(1, scoreBandRange) * 2;
+  const totalXP = Math.max(0, profile.totalXP - xpLoss);
+  const nextProfile: UserProfileWithHistory = {
+    ...profile,
+    totalXP,
+    level: calculateLevel(totalXP),
+    questionsAnswered: profile.questionsAnswered + 1,
+    answeredQuestionIds: profile.answeredQuestionIds.includes(questionId)
+      ? profile.answeredQuestionIds
+      : [...profile.answeredQuestionIds, questionId],
+    lastUpdated: Date.now(),
+  };
+
+  saveUserProfile(nextProfile);
+  return nextProfile;
+}
