+    return stored ? { ...defaultProfile, ...JSON.parse(stored) } : defaultProfile;
+  } catch {
+    return defaultProfile;
+  }
+}
+
+export function saveUserProfile(profile: UserProfileWithHistory) {
+  if (typeof window === "undefined") return;
+  localStorage.setItem(USER_PROFILE_KEY, JSON.stringify(profile));
+}
+
+export function addXPForCorrectAnswer(
+  questionId: string,
+  scoreBandRange = 1
+): UserProfileWithHistory {
+  const profile = getUserProfile();
+  const xpGain = Math.max(1, scoreBandRange) * 10;
+  const nextProfile: UserProfileWithHistory = {
+    ...profile,
+    totalXP: profile.totalXP + xpGain,
+    level: calculateLevel(profile.totalXP + xpGain),
+    questionsAnswered: profile.questionsAnswered + 1,
+    correctAnswers: profile.correctAnswers + 1,
+    answeredQuestionIds: profile.answeredQuestionIds.includes(questionId)
+      ? profile.answeredQuestionIds
+      : [...profile.answeredQuestionIds, questionId],
+    lastUpdated: Date.now(),
+  };
