import * as React from "react";
import { cn } from "@/lib/utils";

export function EmptyState({
  className,
  title,
  description,
  action,
  icon,
}: React.HTMLAttributes<HTMLDivElement> & {
  title?: React.ReactNode;
  description?: React.ReactNode;
  action?:
    | React.ReactNode
    | { label: string; onClick: () => void; icon?: React.ReactNode };
  icon?: React.ReactNode;
  icons?: React.ReactNode[];
  theme?: "light" | "dark";
  size?: "default" | "sm" | "lg";
}) {
  const renderedAction =
    action && typeof action === "object" && "label" in action ? (
      <button
        type="button"
        className="rounded-md border bg-background px-3 py-2 text-sm"
        onClick={action.onClick}
      >
        {action.icon}
        {action.label}
      </button>
    ) : (
      action
    );

  return (
    <div
      className={cn(
        "flex flex-col items-center justify-center gap-3 rounded-lg border p-8 text-center",
        className
      )}
    >
      {icon || (props.icons ? <MultiIconDisplay icons={props.icons} /> : null)}
      {title && <h3 className="text-lg font-semibold">{title}</h3>}
      {description && (
        <p className="max-w-md text-sm text-muted-foreground">{description}</p>
      )}
      {renderedAction}
    </div>
  );
}

export function MultiIconDisplay({
  icons = [],
}: {
  icons?: React.ReactNode[];
}) {
  return (
    <div className="flex items-center justify-center -space-x-2">
      {icons.map((icon, index) => (
        <div
          key={index}
          className="flex size-9 items-center justify-center rounded-full border bg-background"
        >
          {icon}
        </div>
      ))}
    </div>
  );
}

